/// <summary>
/// Roslyn Incremental Source Generator for ATProtocol Lexicon files.
/// </summary>
[Generator(LanguageNames.CSharp)]
public sealed class LexiconGenerator : IIncrementalGenerator
{
    public void Initialize(IncrementalGeneratorInitializationContext context)
    {
        // Filter to only files marked as LexiconFiles (via IsATProtoLexicon metadata)
        var lexiconFiles = context.AdditionalTextsProvider
            .Combine(context.AnalyzerConfigOptionsProvider)
            .Where(static pair =>
            {
                var (file, optionsProvider) = pair;
                var options = optionsProvider.GetOptions(file);
                return options.TryGetValue("build_metadata.AdditionalFiles.IsATProtoLexicon", out var isLexicon)
                       && isLexicon.Equals("true", StringComparison.OrdinalIgnoreCase);
            })
            .Select(static (pair, _) => pair.Left);

        // Parse each lexicon file
        var lexicons = lexiconFiles.Select(static (file, ct) =>
        {
            var content = file.GetText(ct)?.ToString();
            var document = LexiconParser.Parse(content);
            return (Path: file.Path, Document: document);
        }).Where(static x => x.Document != null);

        // Collect all lexicons
        var allLexicons = lexicons.Collect();

        // Get configuration from MSBuild properties
        var configOptions = context.AnalyzerConfigOptionsProvider.Select(static (provider, _) =>
        {
            var options = new GeneratorOptions();

            if (provider.GlobalOptions.TryGetValue("build_property.CarpaNet_RootNamespace", out var rootNs)
                && !string.IsNullOrWhiteSpace(rootNs))
            {
                options.RootNamespace = rootNs;
            }

            if (provider.GlobalOptions.TryGetValue("build_property.CarpaNet_EmitValidationAttributes", out var emitValidation)
                && bool.TryParse(emitValidation, out var emitValidationValue))
            {
                options.EmitValidationAttributes = emitValidationValue;
            }

            if (provider.GlobalOptions.TryGetValue("build_property.CarpaNet_CborContextName", out var cborContextName)
                && !string.IsNullOrWhiteSpace(cborContextName))
            {
                options.CborContextName = cborContextName;
            }

            if (provider.GlobalOptions.TryGetValue("build_property.CarpaNet_JsonContextName", out var jsonContextName)
                && !string.IsNullOrWhiteSpace(jsonContextName))
            {
                options.JsonContextName = jsonContextName;
            }

            return options;
        });

        // Combine lexicons with configuration
        var combined = allLexicons.Combine(configOptions);

        // Register source output
        context.RegisterSourceOutput(combined, static (ctx, data) => GenerateSource(ctx, data.Left, data.Right));
    }

    private static void GenerateSource(
        SourceProductionContext context,
        ImmutableArray<(string Path, LexiconDocument? Document)> lexicons,
        GeneratorOptions options)
    {
        if (lexicons.IsDefaultOrEmpty)
        {
            return;
        }

        var rootNamespace = options.RootNamespace;

        // PHASE 1: Build type registry from all documents
        var registry = new TypeRegistry(rootNamespace);
        var documents = new List<LexiconDocument>();

        foreach (var (path, document) in lexicons)
        {
            if (document == null) continue;
            documents.Add(document);
            registry.RegisterDocument(document);
        }

        // PHASE 2: Group by namespace
        var byNamespace = new Dictionary<string, List<(string Nsid, LexiconDocument Doc)>>();

        foreach (var document in documents)
        {
            var ns = NsidHelper.ToNamespace(document.Id, rootNamespace);

            if (!byNamespace.TryGetValue(ns, out var list))
            {
                list = new List<(string, LexiconDocument)>();
                byNamespace[ns] = list;
            }

            list.Add((document.Id, document));
        }

        // PHASE 3: Generate source for each namespace
        foreach (var kvp in byNamespace)
        {
            var source = GenerateNamespaceSource(kvp.Key, kvp.Value, registry, context, options);
            if (!string.IsNullOrEmpty(source))
            {
                var fileName = kvp.Key.Replace(".", "_") + ".g.cs";
                context.AddSource(fileName, SourceText.From(source, Encoding.UTF8));
            }
        }

        // PHASE 3.5: Generate union interface implementations for cross-namespace types
        var unionMappings = CollectUnionImplementations(byNamespace, registry);
        var unionImplSource = GenerateUnionImplementationsSource(unionMappings);
        if (!string.IsNullOrEmpty(unionImplSource))
        {
            context.AddSource("UnionImplementations.g.cs", SourceText.From(unionImplSource, Encoding.UTF8));
        }

        // PHASE 4: Generate API extensions file
        var extensionsSource = GenerateExtensionsSource(byNamespace, registry, context, options);
        if (!string.IsNullOrEmpty(extensionsSource))
        {
            context.AddSource("ATProtoExtensions.g.cs", SourceText.From(extensionsSource, Encoding.UTF8));
        }

        // PHASE 5: Generate CBOR serialization context
        var cborSource = GenerateCborContextSource(byNamespace, registry, context, options);
        if (!string.IsNullOrEmpty(cborSource))
        {
            context.AddSource("ATProtoCborContext.g.cs", SourceText.From(cborSource, Encoding.UTF8));
        }

        // PHASE 6: Generate JSON serialization context
        var (jsonSource, concreteTypes) = GenerateJsonContextSource(byNamespace, registry, context, options);
        if (!string.IsNullOrEmpty(jsonSource))
        {
            context.AddSource($"{options.JsonContextName}.g.cs", SourceText.From(jsonSource, Encoding.UTF8));
        }

        // PHASE 6.5: Generate ToJson()/FromJson() serialization helper methods on concrete types
        var serializationMethodsSource = GenerateSerializationMethodsSource(concreteTypes, options);
        if (!string.IsNullOrEmpty(serializationMethodsSource))
        {
            context.AddSource("SerializationMethods.g.cs", SourceText.From(serializationMethodsSource, Encoding.UTF8));
        }

        // PHASE 7: Generate client factory class
        var factorySource = GenerateFactorySource(options);
        if (!string.IsNullOrEmpty(factorySource))
        {
            context.AddSource("ATProtoClientFactory.g.cs", SourceText.From(factorySource, Encoding.UTF8));
        }
    }

    private static string GenerateNamespaceSource(
        string ns,
        List<(string Nsid, LexiconDocument Doc)> documents,
        TypeRegistry registry,
        SourceProductionContext context,
        GeneratorOptions options)
    {
        var sb = new SourceBuilder();
        sb.WriteHeader();
        sb.WriteUsing("System");
        sb.WriteUsing("System.Collections.Generic");
        sb.WriteUsing("CarpaNet.Validation");
        sb.WriteUsing("System.Text.Json.Serialization");
        sb.AppendLine();
        sb.WriteNamespace(ns);

        foreach (var (nsid, doc) in documents)
        {
            try
            {
                GenerateDefinitions(sb, nsid, doc, ns, registry, context);
            }
            catch (Exception ex)
            {
                context.ReportDiagnostic(Diagnostic.Create(
                    new DiagnosticDescriptor(
                        "ATPG001",
                        "Generation Error",
                        "Error generating code for {0}: {1}",
                        "CarpaNet",
                        DiagnosticSeverity.Warning,
                        isEnabledByDefault: true),
                    Location.None,
                    nsid,
                    ex.Message));
            }
        }

        return sb.ToString();
    }

    private static void GenerateDefinitions(
        SourceBuilder sb,
        string nsid,
        LexiconDocument doc,
        string currentNamespace,
        TypeRegistry registry,
        SourceProductionContext context)
    {
        foreach (var def in doc.Defs)
        {
            var defName = def.Key;
            var defValue = def.Value;

            // Determine class name - prefix non-main defs with main type name to avoid collisions
            var mainTypeName = NsidHelper.ToTypeName(nsid);
            var className = defName == "main"
                ? mainTypeName
                : mainTypeName + NsidHelper.ToPascalCase(defName);

            switch (defValue.Type)
            {
                case "record":
                    GenerateRecordType(sb, className, defValue, nsid, registry);
                    break;

                case "query":
                    GenerateQueryType(sb, className, defValue, nsid, currentNamespace, registry);
                    break;

                case "procedure":
                    GenerateProcedureType(sb, className, defValue, nsid, currentNamespace, registry);
                    break;

                case "subscription":
                    GenerateSubscriptionType(sb, className, defValue, nsid, currentNamespace, registry);
                    break;

                case "object":
                    ObjectGenerator.GenerateClass(sb, className, defValue, nsid, registry);
                    sb.AppendLine();
                    break;

                case "array":
                    // Array types with union items need to generate the union interface
                    if (defValue.Items?.Type == "union" && defValue.Items.Refs != null)
                    {
                        var interfaceName = $"I{className}";
                        UnionGenerator.GenerateUnionInterface(sb, interfaceName, defValue.Items, nsid, registry);
                        sb.AppendLine();
                    }
                    break;

                case "string":
                    // String types with knownValues/enum are handled as string primitives
                    // No class generation needed - refs resolve to "string"
                    break;

                case "token":
                    // Tokens are string constants - refs resolve to "string"
                    // Optionally generate a static class with the token value
                    GenerateToken(sb, className, defValue, nsid);
                    break;
            }
        }
    }

    private static void GenerateRecordType(
        SourceBuilder sb,
        string className,
        LexiconDefinition def,
        string nsid,
        TypeRegistry registry)
    {
        if (def.Record == null)
        {
            return;
        }

        ObjectGenerator.GenerateClass(
            sb,
            className,
            def.Record,
            nsid,
            registry,
            isRecord: true,
            recordType: nsid);

        sb.AppendLine();
    }

    private static void GenerateQueryType(
        SourceBuilder sb,
        string className,
        LexiconDefinition def,
        string nsid,
        string currentNamespace,
        TypeRegistry registry)
    {
        // Generate parameters class if needed
        if (def.Parameters?.Properties != null && def.Parameters.Properties.Count > 0)
        {
            ApiGenerator.GenerateParametersClass(sb, className, def, nsid, registry);
            sb.AppendLine();
        }

        // Generate output class (skip if schema is a direct ref — the referenced type already exists)
        if (def.Output?.Schema != null && !ApiGenerator.IsOutputRef(def))
        {
            ApiGenerator.GenerateOutputClass(sb, className, def.Output, nsid, registry);
            sb.AppendLine();
        }

        // Generate error constants
        if (def.Errors != null && def.Errors.Count > 0)
        {
            ApiGenerator.GenerateErrorClasses(sb, className, def.Errors, nsid);
            sb.AppendLine();
        }
    }

