    private static void GenerateToken(
        SourceBuilder sb,
        string className,
        LexiconDefinition def,
        string nsid)
    {
        sb.WriteSummary(def.Description ?? $"Token: {nsid}#{className}");
        sb.AppendLine($"public static class {className}Token");
        sb.OpenBrace();
        sb.AppendLine($"public const string Value = \"{nsid}#{NsidHelper.ToCamelCase(className)}\";");
        sb.CloseBrace();
        sb.AppendLine();
    }

    private static string GenerateExtensionsSource(
        Dictionary<string, List<(string Nsid, LexiconDocument Doc)>> byNamespace,
        TypeRegistry registry,
        SourceProductionContext context,
        GeneratorOptions options)
    {
        var sb = new SourceBuilder();
        sb.WriteHeader();
        sb.WriteUsing("System");
        sb.WriteUsing("System.Collections.Generic");
        sb.WriteUsing("System.Threading");
        sb.WriteUsing("System.Threading.Tasks");
        sb.AppendLine();

        var extensionsNs = string.IsNullOrEmpty(options.RootNamespace)
            ? "CarpaNet.Extensions"
            : $"{options.RootNamespace}.Extensions";
        sb.WriteNamespace(extensionsNs);

        sb.WriteSummary("Extension methods for ATProto API calls.");
        sb.AppendLine("public static partial class ATProtoClientExtensions");
        sb.OpenBrace();

        foreach (var kvp in byNamespace)
        {
            var ns = kvp.Key;

            foreach (var (nsid, doc) in kvp.Value)
            {
                foreach (var def in doc.Defs)
                {
                    if (def.Key != "main") continue;

                    var className = NsidHelper.ToTypeName(nsid);

                    switch (def.Value.Type)
                    {
                        case "query":
                            ApiGenerator.GenerateQueryExtension(sb, className, def.Value, nsid, ns, registry);
                            sb.AppendLine();
                            break;

                        case "procedure":
                            ApiGenerator.GenerateProcedureExtension(sb, className, def.Value, nsid, ns, registry);
                            sb.AppendLine();
                            break;

                        case "subscription":
                            ApiGenerator.GenerateSubscriptionExtension(sb, className, def.Value, nsid, ns, registry);
                            sb.AppendLine();
                            break;
                    }
                }
            }
        }

        sb.CloseBrace();

        return sb.ToString();
    }

    private static string GenerateCborContextSource(
        Dictionary<string, List<(string Nsid, LexiconDocument Doc)>> byNamespace,
        TypeRegistry registry,
        SourceProductionContext context,
        GeneratorOptions options)
    {
        var sb = new SourceBuilder();
        sb.WriteHeader();
        sb.AppendLine();

        var generatedTypes = new HashSet<string>();

        // Collect all type registrations: (ClassSuffix, QualifiedTypeName, TypeDiscriminator)
        var typesToRegister = new List<(string ClassSuffix, string QualifiedTypeName, string? TypeDiscriminator)>();

        // Single namespace for all CBOR type info classes (matches JSON generator pattern)
        var contextNs = string.IsNullOrEmpty(options.RootNamespace)
            ? "CarpaNet.Cbor"
            : $"{options.RootNamespace}.Cbor";

        sb.WriteNamespace(contextNs);

        // Iterate all namespaces and types to generate CborTypeInfo classes
        foreach (var kvp in byNamespace)
        {
            var ns = kvp.Key;

            foreach (var (nsid, doc) in kvp.Value)
            {
                foreach (var def in doc.Defs)
                {
                    var defName = def.Key;
                    var defValue = def.Value;

                    var mainTypeName = NsidHelper.ToTypeName(nsid);
                    var className = defName == "main"
                        ? mainTypeName
                        : mainTypeName + NsidHelper.ToPascalCase(defName);

                    switch (defValue.Type)
                    {
                        case "record":
                            if (defValue.Record != null)
                            {
                                var fullName = $"{ns}.{className}";
                                var suffix = CborContextGenerator.ToClassSuffix(fullName);
                                CborContextGenerator.GenerateCborTypeInfo(sb, fullName, suffix, defValue.Record, nsid, registry, options, isRecord: true, generatedTypes: generatedTypes);
                                typesToRegister.Add((suffix, fullName, nsid));
                            }
                            break;

                        case "object":
                        {
                            var fullName = $"{ns}.{className}";
                            var suffix = CborContextGenerator.ToClassSuffix(fullName);
                            CborContextGenerator.GenerateCborTypeInfo(sb, fullName, suffix, defValue, nsid, registry, options, generatedTypes: generatedTypes);
                            typesToRegister.Add((suffix, fullName, null));
                            break;
                        }

                        case "union":
                            if (defValue.Refs != null)
                            {
                                var interfaceName = $"I{className}";
                                var fullName = $"{ns}.{interfaceName}";
                                var suffix = CborContextGenerator.ToClassSuffix(fullName);
                                CborContextGenerator.GenerateCborUnionTypeInfo(sb, fullName, suffix, defValue.Refs, nsid, registry, options, generatedTypes);
                                typesToRegister.Add((suffix, fullName, null));
                            }
                            break;

                        case "query":
                            if (defValue.Output?.Schema != null && !ApiGenerator.IsOutputRef(defValue))
                            {
                                var outputClassName = className + "Output";
                                var fullName = $"{ns}.{outputClassName}";
                                var suffix = CborContextGenerator.ToClassSuffix(fullName);
                                CborContextGenerator.GenerateCborTypeInfo(sb, fullName, suffix, defValue.Output.Schema, nsid, registry, options, generatedTypes: generatedTypes);
                                typesToRegister.Add((suffix, fullName, null));
                            }
                            break;

                        case "procedure":
                            if (defValue.Input?.Schema != null && !ApiGenerator.IsInputRef(defValue))
                            {
                                var inputClassName = className + "Input";
                                var fullName = $"{ns}.{inputClassName}";
                                var suffix = CborContextGenerator.ToClassSuffix(fullName);
                                CborContextGenerator.GenerateCborTypeInfo(sb, fullName, suffix, defValue.Input.Schema, nsid, registry, options, generatedTypes: generatedTypes);
                                typesToRegister.Add((suffix, fullName, null));
                            }
                            if (defValue.Output?.Schema != null && !ApiGenerator.IsOutputRef(defValue))
                            {
                                var outputClassName = className + "Output";
                                var fullName = $"{ns}.{outputClassName}";
                                var suffix = CborContextGenerator.ToClassSuffix(fullName);
                                CborContextGenerator.GenerateCborTypeInfo(sb, fullName, suffix, defValue.Output.Schema, nsid, registry, options, generatedTypes: generatedTypes);
                                typesToRegister.Add((suffix, fullName, null));
                            }
                            break;

                        case "subscription":
                            if (defValue.Parameters?.Properties != null && defValue.Parameters.Properties.Count > 0)
                            {
                                var paramsClassName = className + "Parameters";
                                var fullName = $"{ns}.{paramsClassName}";
                                var suffix = CborContextGenerator.ToClassSuffix(fullName);
                                CborContextGenerator.GenerateCborTypeInfo(sb, fullName, suffix, defValue.Parameters, nsid, registry, options, generatedTypes: generatedTypes);
                                typesToRegister.Add((suffix, fullName, null));
                            }
                            if (defValue.Message?.Schema?.Type == "union" && defValue.Message.Schema.Refs != null)
                            {
                                var interfaceName = $"I{className}Message";
                                var fullName = $"{ns}.{interfaceName}";
                                var suffix = CborContextGenerator.ToClassSuffix(fullName);
                                CborContextGenerator.GenerateCborUnionTypeInfo(sb, fullName, suffix, defValue.Message.Schema.Refs, nsid, registry, options, generatedTypes);
                                typesToRegister.Add((suffix, fullName, null));
                            }
                            break;

                        case "array":
                            if (defValue.Items?.Type == "union" && defValue.Items.Refs != null)
                            {
                                var interfaceName = $"I{className}";
                                var fullName = $"{ns}.{interfaceName}";
                                var suffix = CborContextGenerator.ToClassSuffix(fullName);
                                CborContextGenerator.GenerateCborUnionTypeInfo(sb, fullName, suffix, defValue.Items.Refs, nsid, registry, options, generatedTypes);
                                typesToRegister.Add((suffix, fullName, null));
                            }
                            break;
                    }
                }
            }
        }

        // Generate the context class
        sb.WriteSummary("AOT-compatible CBOR serialization context for all AT Protocol types.");
        sb.AppendLine($"public partial class {options.CborContextName} : CarpaNet.Cbor.CborSerializerContext");
        sb.OpenBrace();

        sb.WriteSummary("Gets the default singleton instance.");
        sb.AppendLine($"public static new {options.CborContextName} Default {{ get; }} = new {options.CborContextName}();");
        sb.AppendLine();

        sb.WriteSummary("Initializes a new instance and registers all AT Protocol types.");
        sb.AppendLine($"public {options.CborContextName}()");
        sb.OpenBrace();

        foreach (var type in typesToRegister)
        {
            sb.AppendLine($"RegisterTypeInfo(new {type.ClassSuffix}CborTypeInfo());");

            if (!string.IsNullOrEmpty(type.TypeDiscriminator))
            {
                sb.AppendLine($"RegisterDerivedType(\"{type.TypeDiscriminator}\", typeof(global::{type.QualifiedTypeName}));");
            }
        }

        sb.CloseBrace(); // constructor
        sb.CloseBrace(); // class

        return sb.ToString();
    }

    private static (string Source, HashSet<string> ConcreteTypes) GenerateJsonContextSource(
        Dictionary<string, List<(string Nsid, LexiconDocument Doc)>> byNamespace,
        TypeRegistry registry,
        SourceProductionContext context,
        GeneratorOptions options)
    {
        var sb = new SourceBuilder();
        sb.WriteHeader();
        sb.AppendLine("#if NET8_0_OR_GREATER");
        sb.AppendLine();

        var generatedTypes = new HashSet<string>();
        var collectedPropertyTypes = new HashSet<string>();
        var nestedTypeDispatch = new List<(string FullTypeName, string MethodSuffix)>();
        var concreteTypes = new HashSet<string>();

        // Collect all type dispatch entries: (fullCSharpTypeName, methodSuffix)
        var typeDispatch = new List<(string FullTypeName, string MethodSuffix)>();

        var contextNs = string.IsNullOrEmpty(options.RootNamespace)
            ? "CarpaNet.Json"
            : $"{options.RootNamespace}.Json";

        sb.WriteNamespace(contextNs);

        sb.WriteSummary("AOT-compatible JSON serialization context implementing IJsonTypeInfoResolver for all AT Protocol types.");
        sb.AppendLine($"public sealed class {options.JsonContextName} : global::System.Text.Json.Serialization.Metadata.IJsonTypeInfoResolver");
        sb.OpenBrace();

        sb.WriteSummary("Gets the default singleton instance.");
        sb.AppendLine($"public static {options.JsonContextName} Default {{ get; }} = new {options.JsonContextName}();");
        sb.AppendLine();

        // Default options for use by serialization helper methods
        sb.AppendLine("private static readonly global::System.Text.Json.JsonSerializerOptions s_defaultOptions = new global::System.Text.Json.JsonSerializerOptions");
        sb.OpenBrace();
        sb.AppendLine("PropertyNamingPolicy = global::System.Text.Json.JsonNamingPolicy.CamelCase,");
        sb.AppendLine("DefaultIgnoreCondition = global::System.Text.Json.Serialization.JsonIgnoreCondition.WhenWritingNull,");
        sb.AppendLine($"TypeInfoResolver = Default,");
        sb.CloseBrace(withSemicolon: true);
        sb.AppendLine();

        sb.WriteSummary("Gets the default JsonSerializerOptions configured with the generated JSON type info resolver.");
        sb.AppendLine("public static global::System.Text.Json.JsonSerializerOptions DefaultOptions => s_defaultOptions;");
        sb.AppendLine();

        // Iterate all namespaces and types to generate factory methods
        foreach (var kvp in byNamespace)
        {
            var ns = kvp.Key;

            foreach (var (nsid, doc) in kvp.Value)
            {
                foreach (var def in doc.Defs)
                {
                    var defName = def.Key;
                    var defValue = def.Value;

                    var mainTypeName = NsidHelper.ToTypeName(nsid);
                    var className = defName == "main"
                        ? mainTypeName
                        : mainTypeName + NsidHelper.ToPascalCase(defName);

                    switch (defValue.Type)
                    {
                        case "record":
                            if (defValue.Record != null)
                            {
                                var fullName = $"{ns}.{className}";
                                var suffix = JsonContextGenerator.ToMethodSuffix(fullName);
                                JsonContextGenerator.GenerateJsonTypeInfo(sb, fullName, suffix, defValue.Record, nsid, registry, options, isRecord: true, generatedTypes: generatedTypes, collectedPropertyTypes: collectedPropertyTypes, nestedTypeDispatch: nestedTypeDispatch, concreteTypes: concreteTypes);
                                typeDispatch.Add((fullName, suffix));
                            }
                            break;

                        case "object":
                        {
                            var fullName = $"{ns}.{className}";
                            var suffix = JsonContextGenerator.ToMethodSuffix(fullName);
                            JsonContextGenerator.GenerateJsonTypeInfo(sb, fullName, suffix, defValue, nsid, registry, options, generatedTypes: generatedTypes, collectedPropertyTypes: collectedPropertyTypes, nestedTypeDispatch: nestedTypeDispatch, concreteTypes: concreteTypes);
                            typeDispatch.Add((fullName, suffix));
                            break;
                        }

                        case "union":
                            if (defValue.Refs != null)
                            {
                                var interfaceName = $"I{className}";
                                var fullName = $"{ns}.{interfaceName}";
                                var suffix = JsonContextGenerator.ToMethodSuffix(fullName);
                                JsonContextGenerator.GenerateJsonUnionTypeInfo(sb, fullName, suffix, defValue.Refs, nsid, registry, options, isClosed: defValue.Closed == true, generatedTypes: generatedTypes, nestedTypeDispatch: nestedTypeDispatch);
                                typeDispatch.Add((fullName, suffix));
                            }
                            break;

                        case "query":
                            if (defValue.Output?.Schema != null && !ApiGenerator.IsOutputRef(defValue))
                            {
                                var outputClassName = className + "Output";
                                var fullName = $"{ns}.{outputClassName}";
                                var suffix = JsonContextGenerator.ToMethodSuffix(fullName);
                                JsonContextGenerator.GenerateJsonTypeInfo(sb, fullName, suffix, defValue.Output.Schema, nsid, registry, options, generatedTypes: generatedTypes, collectedPropertyTypes: collectedPropertyTypes, nestedTypeDispatch: nestedTypeDispatch, concreteTypes: concreteTypes);
                                typeDispatch.Add((fullName, suffix));
                            }
                            break;

                        case "procedure":
                            if (defValue.Input?.Schema != null && !ApiGenerator.IsInputRef(defValue))
                            {
                                var inputClassName = className + "Input";
                                var fullName = $"{ns}.{inputClassName}";
                                var suffix = JsonContextGenerator.ToMethodSuffix(fullName);
                                JsonContextGenerator.GenerateJsonTypeInfo(sb, fullName, suffix, defValue.Input.Schema, nsid, registry, options, generatedTypes: generatedTypes, collectedPropertyTypes: collectedPropertyTypes, nestedTypeDispatch: nestedTypeDispatch, concreteTypes: concreteTypes);
                                typeDispatch.Add((fullName, suffix));
                            }
                            if (defValue.Output?.Schema != null && !ApiGenerator.IsOutputRef(defValue))
                            {
                                var outputClassName = className + "Output";
                                var fullName = $"{ns}.{outputClassName}";
                                var suffix = JsonContextGenerator.ToMethodSuffix(fullName);
                                JsonContextGenerator.GenerateJsonTypeInfo(sb, fullName, suffix, defValue.Output.Schema, nsid, registry, options, generatedTypes: generatedTypes, collectedPropertyTypes: collectedPropertyTypes, nestedTypeDispatch: nestedTypeDispatch, concreteTypes: concreteTypes);
                                typeDispatch.Add((fullName, suffix));
                            }
                            break;

                        case "subscription":
                            if (defValue.Message?.Schema?.Type == "union" && defValue.Message.Schema.Refs != null)
                            {
                                var interfaceName = $"I{className}Message";
                                var fullName = $"{ns}.{interfaceName}";
                                var suffix = JsonContextGenerator.ToMethodSuffix(fullName);
                                JsonContextGenerator.GenerateJsonUnionTypeInfo(sb, fullName, suffix, defValue.Message.Schema.Refs, nsid, registry, options, isClosed: defValue.Message.Schema.Closed == true, generatedTypes: generatedTypes, nestedTypeDispatch: nestedTypeDispatch);
                                typeDispatch.Add((fullName, suffix));
                            }
                            break;

                        case "array":
                            if (defValue.Items?.Type == "union" && defValue.Items.Refs != null)
                            {
                                var interfaceName = $"I{className}";
                                var fullName = $"{ns}.{interfaceName}";
                                var suffix = JsonContextGenerator.ToMethodSuffix(fullName);
                                JsonContextGenerator.GenerateJsonUnionTypeInfo(sb, fullName, suffix, defValue.Items.Refs, nsid, registry, options, isClosed: defValue.Items.Closed == true, generatedTypes: generatedTypes, nestedTypeDispatch: nestedTypeDispatch);
                                typeDispatch.Add((fullName, suffix));
                            }
                            break;
                    }
                }
            }
        }

        // Merge nested type dispatch entries (inline objects/unions generated recursively)
        typeDispatch.AddRange(nestedTypeDispatch);

        // Generate built-in type info factories for leaf property types (primitives, runtime types, List<T>)
        var generatedObjectTypeNames = new HashSet<string>(typeDispatch.Select(t => t.FullTypeName.Replace("@", "")));
        var builtInDispatchLines = JsonContextGenerator.GenerateBuiltInTypeInfos(sb, collectedPropertyTypes, generatedObjectTypeNames);

        // Generate the GetTypeInfo dispatch method
        sb.WriteSummary("Gets the JSON type info for the specified type, or null if not handled.");
        sb.AppendLine("public global::System.Text.Json.Serialization.Metadata.JsonTypeInfo? GetTypeInfo(global::System.Type type, global::System.Text.Json.JsonSerializerOptions options)");
        sb.OpenBrace();

        foreach (var entry in typeDispatch)
        {
            sb.AppendLine($"if (type == typeof(global::{entry.FullTypeName})) return Create_{entry.MethodSuffix}_TypeInfo(options);");
        }

        // Built-in type dispatch (primitives, runtime types, nullables, collections)
        foreach (var line in builtInDispatchLines)
        {
            sb.AppendLine(line);
        }

        sb.AppendLine("return null;");
        sb.CloseBrace();

        sb.CloseBrace(); // class
        sb.AppendLine();
        sb.AppendLine("#endif");

        return (sb.ToString(), concreteTypes);
    }

    private static string GenerateSerializationMethodsSource(
        HashSet<string> concreteTypes,
        GeneratorOptions options)
    {
        if (concreteTypes.Count == 0)
        {
            return string.Empty;
        }

        var contextNs = string.IsNullOrEmpty(options.RootNamespace)
            ? "CarpaNet.Json"
            : $"{options.RootNamespace}.Json";

        var sb = new SourceBuilder();
        sb.WriteHeader();
        sb.AppendLine("#if NET8_0_OR_GREATER");
        sb.AppendLine();

        // Group types by namespace
        var byNamespace = concreteTypes
            .OrderBy(t => t)
            .GroupBy(t => t.Contains(".")
                ? t.Substring(0, t.LastIndexOf('.'))
                : "");

        foreach (var nsGroup in byNamespace)
        {
            var ns = nsGroup.Key;
            if (!string.IsNullOrEmpty(ns))
            {
                sb.WriteNamespaceBlock(ns);
            }

            foreach (var fullTypeName in nsGroup)
            {
                var shortName = fullTypeName.Contains(".")
                    ? fullTypeName.Substring(fullTypeName.LastIndexOf('.') + 1)
                    : fullTypeName;

                sb.AppendLine($"partial class {shortName}");
                sb.OpenBrace();

                // ToJson()
                sb.WriteSummary("Serializes this instance to a <see cref=\"global::System.Text.Json.JsonElement\"/>.");
                sb.AppendLine("public global::System.Text.Json.JsonElement ToJson()");
                sb.OpenBrace();
                sb.AppendLine("return global::System.Text.Json.JsonSerializer.SerializeToElement(");
                sb.Indent();
                sb.AppendLine("this,");
                sb.AppendLine($"(global::System.Text.Json.Serialization.Metadata.JsonTypeInfo<{shortName}>)");
                sb.AppendLine($"    global::{contextNs}.{options.JsonContextName}.DefaultOptions.GetTypeInfo(typeof({shortName}))!);");
                sb.Unindent();
                sb.CloseBrace();
                sb.AppendLine();

                // FromJson()
                sb.WriteSummary("Deserializes a <see cref=\"global::System.Text.Json.JsonElement\"/> to an instance of this type.");
                sb.AppendLine($"public static {shortName}? FromJson(global::System.Text.Json.JsonElement element)");
                sb.OpenBrace();
                sb.AppendLine($"return global::System.Text.Json.JsonSerializer.Deserialize(");
                sb.Indent();
                sb.AppendLine("element,");
                sb.AppendLine($"(global::System.Text.Json.Serialization.Metadata.JsonTypeInfo<{shortName}>)");
                sb.AppendLine($"    global::{contextNs}.{options.JsonContextName}.DefaultOptions.GetTypeInfo(typeof({shortName}))!);");
                sb.Unindent();
                sb.CloseBrace();

                sb.CloseBrace(); // partial class
                sb.AppendLine();
            }

            if (!string.IsNullOrEmpty(ns))
            {
                sb.CloseBrace(); // namespace
                sb.AppendLine();
            }
        }

        sb.AppendLine("#endif");

        return sb.ToString();
    }

    /// <summary>
    /// Collects all union interface-to-implementation mappings across all namespaces.
    /// Returns a mapping of fully-qualified derived type name -> set of fully-qualified interface names.
    /// </summary>
    private static Dictionary<string, HashSet<string>> CollectUnionImplementations(
        Dictionary<string, List<(string Nsid, LexiconDocument Doc)>> byNamespace,
        TypeRegistry registry)
    {
        var result = new Dictionary<string, HashSet<string>>();

        void AddMapping(string derivedType, string interfaceName)
        {
            if (!result.TryGetValue(derivedType, out var set))
            {
                set = new HashSet<string>();
                result[derivedType] = set;
            }
            set.Add(interfaceName);
        }

        void ProcessUnionRefs(List<string> refs, string fullyQualifiedInterfaceName, string currentNsid)
        {
            foreach (var refString in refs)
            {
                var fullRef = refString.StartsWith("#") ? $"{currentNsid}{refString}" : refString;
                var typeInfo = registry.Lookup(fullRef);

                // Only add mapping for concrete class types (object/record)
                if (typeInfo != null && (typeInfo.Kind == LexiconTypeKind.Object || typeInfo.Kind == LexiconTypeKind.Record))
                {
                    AddMapping(typeInfo.FullCSharpTypeName, fullyQualifiedInterfaceName);
                }
            }
        }

        void ProcessObjectProperties(Dictionary<string, LexiconDefinition> properties, string className, string ns, string currentNsid)
        {
            foreach (var prop in properties)
            {
                if (prop.Value.Type == "union" && prop.Value.Refs != null)
                {
                    var cleanClassName = NsidHelper.StripEscapePrefix(className);
                    var cleanPropertyName = NsidHelper.StripEscapePrefix(NsidHelper.ToPascalCase(prop.Key));
                    var interfaceName = $"I{cleanClassName}{cleanPropertyName}";
                    var fullyQualifiedInterface = $"{ns}.{interfaceName}";
                    ProcessUnionRefs(prop.Value.Refs, fullyQualifiedInterface, currentNsid);
                }

                if (prop.Value.Type == "array" && prop.Value.Items?.Type == "union" && prop.Value.Items.Refs != null)
                {
                    var cleanClassName = NsidHelper.StripEscapePrefix(className);
                    var cleanPropertyName = NsidHelper.StripEscapePrefix(NsidHelper.ToPascalCase(prop.Key));
                    var interfaceName = $"I{cleanClassName}{cleanPropertyName}";
                    var fullyQualifiedInterface = $"{ns}.{interfaceName}";
                    ProcessUnionRefs(prop.Value.Items.Refs, fullyQualifiedInterface, currentNsid);
                }
            }
        }

        foreach (var kvp in byNamespace)
        {
            var ns = kvp.Key;

            foreach (var (nsid, doc) in kvp.Value)
            {
                foreach (var def in doc.Defs)
                {
                    var defName = def.Key;
                    var defValue = def.Value;

                    var mainTypeName = NsidHelper.ToTypeName(nsid);
                    var className = defName == "main"
                        ? mainTypeName
                        : mainTypeName + NsidHelper.ToPascalCase(defName);

                    switch (defValue.Type)
                    {
                        case "record":
                            if (defValue.Record?.Properties != null)
                            {
                                ProcessObjectProperties(defValue.Record.Properties, className, ns, nsid);
                            }
                            break;

                        case "object":
                            if (defValue.Properties != null)
                            {
                                ProcessObjectProperties(defValue.Properties, className, ns, nsid);
                            }
                            break;

                        case "union":
                            if (defValue.Refs != null)
                            {
                                var interfaceName = $"I{className}";
                                var fullyQualifiedInterface = $"{ns}.{interfaceName}";
                                ProcessUnionRefs(defValue.Refs, fullyQualifiedInterface, nsid);
                            }
                            break;

                        case "array":
                            if (defValue.Items?.Type == "union" && defValue.Items.Refs != null)
                            {
                                var interfaceName = $"I{className}";
                                var fullyQualifiedInterface = $"{ns}.{interfaceName}";
                                ProcessUnionRefs(defValue.Items.Refs, fullyQualifiedInterface, nsid);
                            }
                            break;

                        case "query":
                            if (defValue.Output?.Schema != null && !ApiGenerator.IsOutputRef(defValue) && defValue.Output.Schema.Properties != null)
                            {
                                var outputClassName = className + "Output";
                                ProcessObjectProperties(defValue.Output.Schema.Properties, outputClassName, ns, nsid);
                            }
                            break;

                        case "procedure":
                            if (defValue.Input?.Schema != null && !ApiGenerator.IsInputRef(defValue) && defValue.Input.Schema.Properties != null)
                            {
                                var inputClassName = className + "Input";
                                ProcessObjectProperties(defValue.Input.Schema.Properties, inputClassName, ns, nsid);
                            }
                            if (defValue.Output?.Schema != null && !ApiGenerator.IsOutputRef(defValue) && defValue.Output.Schema.Properties != null)
                            {
                                var outputClassName = className + "Output";
                                ProcessObjectProperties(defValue.Output.Schema.Properties, outputClassName, ns, nsid);
                            }
                            break;

                        case "subscription":
                            if (defValue.Message?.Schema?.Type == "union" && defValue.Message.Schema.Refs != null)
                            {
                                var interfaceName = $"I{className}Message";
                                var fullyQualifiedInterface = $"{ns}.{interfaceName}";
                                ProcessUnionRefs(defValue.Message.Schema.Refs, fullyQualifiedInterface, nsid);
                            }
                            break;
                    }
                }
            }
        }

        return result;
    }

    /// <summary>
    /// Generates partial class declarations that add union interface implementations.
    /// </summary>
    private static string GenerateUnionImplementationsSource(
        Dictionary<string, HashSet<string>> unionMappings)
    {
        if (unionMappings.Count == 0) return string.Empty;

        var sb = new SourceBuilder();
        sb.WriteHeader();

        // Group by namespace of the derived type
        var byNamespace = new Dictionary<string, List<(string ClassName, HashSet<string> Interfaces)>>();

        foreach (var kvp in unionMappings)
        {
            var lastDot = kvp.Key.LastIndexOf('.');
            if (lastDot < 0) continue;

            var ns = kvp.Key.Substring(0, lastDot);
            var className = kvp.Key.Substring(lastDot + 1);

            if (!byNamespace.TryGetValue(ns, out var list))
            {
                list = new List<(string, HashSet<string>)>();
                byNamespace[ns] = list;
            }

            list.Add((className, kvp.Value));
        }

        foreach (var nsKvp in byNamespace)
        {
            sb.WriteNamespaceBlock(nsKvp.Key);

            foreach (var (className, interfaces) in nsKvp.Value)
            {
                var interfaceList = string.Join(", ", interfaces.OrderBy(i => i).Select(i => $"global::{i}"));
                sb.AppendLine($"public partial class {className} : {interfaceList}");
                sb.OpenBrace();
                sb.CloseBrace();
                sb.AppendLine();
            }

            sb.CloseBrace(); // namespace
            sb.AppendLine();
        }

        return sb.ToString();
    }

    private static string GenerateFactorySource(GeneratorOptions options)
    {
        var sb = new SourceBuilder();
        sb.WriteHeader();
        sb.AppendLine("#if NET8_0_OR_GREATER");
        sb.AppendLine();
        sb.WriteUsing("System");
        sb.WriteUsing("System.Collections.Generic");
        sb.WriteUsing("System.Net.Http");
        sb.WriteUsing("System.Text.Json");
        sb.WriteUsing("System.Text.Json.Serialization");
        sb.WriteUsing("System.Text.Json.Serialization.Metadata");
        sb.WriteUsing("System.Threading");
        sb.WriteUsing("System.Threading.Tasks");
        sb.WriteUsing("CarpaNet");
        sb.WriteUsing("CarpaNet.Cbor");
        sb.WriteUsing("CarpaNet.Identity");
        sb.AppendLine();

        var jsonContextNs = string.IsNullOrEmpty(options.RootNamespace)
            ? "CarpaNet.Json"
            : $"{options.RootNamespace}.Json";

        var cborContextNs = string.IsNullOrEmpty(options.RootNamespace)
            ? "CarpaNet.Cbor"
            : $"{options.RootNamespace}.Cbor";

        var factoryNs = string.IsNullOrEmpty(options.RootNamespace)
            ? "CarpaNet.Extensions"
            : $"{options.RootNamespace}.Extensions";

        sb.WriteNamespace(factoryNs);

        sb.WriteSummary("Factory class that creates pre-configured ATProto client instances with the generated JSON and CBOR serialization contexts.");
        sb.AppendLine("public static class ATProtoClientFactory");
        sb.OpenBrace();

        // CreateJsonOptions
        sb.WriteSummary("Creates JsonSerializerOptions configured with the generated JSON type info resolver.");
        sb.AppendLine("public static JsonSerializerOptions CreateJsonOptions()");
        sb.OpenBrace();
        sb.AppendLine($"return global::{jsonContextNs}.{options.JsonContextName}.DefaultOptions;");
        sb.CloseBrace();
        sb.AppendLine();

        // CreatePublic
        sb.WriteSummary("Creates a public (unauthenticated) ATProtoClient with the generated serialization contexts.");
        sb.AppendLine("public static ATProtoClient CreatePublic(ATProtoClientOptions? options = null)");
        sb.OpenBrace();
        sb.AppendLine("options ??= new ATProtoClientOptions { JsonOptions = CreateJsonOptions(), CborContext = global::" + cborContextNs + "." + options.CborContextName + ".Default };");
        sb.AppendLine("options.BaseUrl ??= new Uri(\"https://public.api.bsky.app\");");
        sb.AppendLine("return new ATProtoClient(options);");
        sb.CloseBrace();
        sb.AppendLine();

        // CreateWithSessionAsync
        sb.WriteSummary("Creates an authenticated ATProtoClient with the generated serialization contexts.");
        sb.AppendLine("public static async Task<ATProtoClient> CreateWithSessionAsync(");
        sb.Indent();
        sb.AppendLine("string identifier, string password,");
        sb.AppendLine("Uri? serviceUrl = null,");
        sb.AppendLine("ATProtoClientOptions? options = null,");
        sb.AppendLine("CancellationToken cancellationToken = default)");
        sb.Unindent();
        sb.OpenBrace();
        sb.AppendLine("options ??= new ATProtoClientOptions { JsonOptions = CreateJsonOptions(), CborContext = global::" + cborContextNs + "." + options.CborContextName + ".Default };");
        sb.AppendLine("return await ATProtoClient.CreateWithSessionAsync(");
        sb.Indent();
        sb.AppendLine("identifier, password, serviceUrl, options, cancellationToken);");
        sb.Unindent();
        sb.CloseBrace();
        sb.AppendLine();

        // CreatePublicClient
        sb.WriteSummary("Creates an ATProtoPublicClient with the generated serialization contexts.");
        sb.AppendLine("public static ATProtoPublicClient CreatePublicClient(");
        sb.Indent();
        sb.AppendLine("HttpClient? httpClient = null,");
        sb.AppendLine("Uri? baseUrl = null,");
        sb.AppendLine("IdentityResolver? identityResolver = null,");
        sb.AppendLine("IReadOnlyList<string>? labelerDids = null)");
        sb.Unindent();
        sb.OpenBrace();
        sb.AppendLine("return new ATProtoPublicClient(");
        sb.Indent();
        sb.AppendLine("httpClient ?? new HttpClient(),");
        sb.AppendLine("CreateJsonOptions(),");
        sb.AppendLine($"global::{cborContextNs}.{options.CborContextName}.Default,");
        sb.AppendLine("baseUrl,");
        sb.AppendLine("identityResolver,");
        sb.AppendLine("labelerDids);");
        sb.Unindent();
        sb.CloseBrace();
        sb.AppendLine();

        // CreateSessionClient
        sb.WriteSummary("Creates an ATProtoSessionClient with the generated serialization contexts.");
        sb.AppendLine("public static ATProtoSessionClient CreateSessionClient(");
        sb.Indent();
        sb.AppendLine("HttpClient? httpClient = null,");
        sb.AppendLine("IdentityResolver? identityResolver = null,");
        sb.AppendLine("IReadOnlyList<string>? labelerDids = null)");
        sb.Unindent();
        sb.OpenBrace();
        sb.AppendLine("return new ATProtoSessionClient(");
        sb.Indent();
        sb.AppendLine("httpClient ?? new HttpClient(),");
        sb.AppendLine("CreateJsonOptions(),");
        sb.AppendLine($"global::{cborContextNs}.{options.CborContextName}.Default,");
        sb.AppendLine("identityResolver,");
        sb.AppendLine("labelerDids);");
        sb.Unindent();
        sb.CloseBrace();

        sb.CloseBrace(); // class
        sb.AppendLine();
        sb.AppendLine("#endif");

        return sb.ToString();
    }
